const content = $json.choices?.[0]?.message?.content;
if (!content) throw new Error("Missing OpenAI content");

let parsed;
try {
  parsed = JSON.parse(content);
} catch (e) {
  throw new Error("OutlineAgent did not return valid JSON: " + content);
