const outline = $('Parse Outline JSON').item.json.outline;
const scriptPack = $('Apply Compliance Fixes').item.json.scriptPack;
const r2Prefix = $('Set Manifest').item.json.r2Prefix;
const statusResponse = $json;

if (!outline) throw new Error('Missing outline');
if (!scriptPack) throw new Error('Missing scriptPack');

// Extract signed URLs from the correct path
const videoUrl = statusResponse?.body?.signed?.videoUrl || statusResponse?.signed?.videoUrl || statusResponse?.videoUrl || '';
const logUrl = statusResponse?.body?.signed?.logUrl || statusResponse?.signed?.logUrl || statusResponse?.logUrl || '';

if (!videoUrl) {
  console.warn('Warning: videoUrl not found in response. Full response:', JSON.stringify(statusResponse, null, 2));
}

const titleBase = outline?.title || scriptPack?.title || 'Automated Realty Playbook';
const youtubeTitle = titleBase.length > 95 ? titleBase.slice(0, 95) : titleBase;

const affiliateDisclosure = 'Disclosure: Some links may be affiliate links. I may earn a commission at no extra cost to you.';

const youtubeDescription = [
  (outline?.hook ? outline.hook + '\n' : ''),
  'In this video, we break down practical ways to use AI to automate your real estate workflow—lead follow-up, listings, content, and deal analysis.',
  '',
  '✅ Subscribe for more AI + real estate automation.',
  '',
  affiliateDisclosure,
  '',
  (scriptPack?.disclaimer || 'Not legal, tax, or financial advice. Consult a professional.')
].join('\n');

const youtubeTags = [
  'ai real estate',
  'real estate automation',
  'chatgpt real estate',
  'real estate ai tools',
  'automated realty playbook'
];

return $input.all().map(item => ({
  json: {
    runId: $('Set Manifest').item.json.runId,
    r2Bucket: $('Set Manifest').item.json.r2Bucket,
    r2Prefix,
    videoUrl,
    logUrl,
    youtubeTitle,
    youtubeDescription,
    youtubeTags,
    hashtags: ['#AI', '#RealEstate', '#Automation'],
    pinnedComment: 'Want the free AI toolkit? Comment TOOLKIT and I will send it.',
    affiliateDisclosure,
    privacyStatus: 'private',
    categoryId: '26'
  },
  pairedItem: item.pairedItem
}));

const manifest = {
  runId: $json.runId,
  r2Bucket: $json.r2Bucket,
  r2Prefix: $json.r2Prefix,
  videoUrl: $json.videoUrl,
  logUrl: $json.logUrl,
  youtube: {
    title: $json.youtubeTitle,
    description: $json.youtubeDescription,
    tags: $json.youtubeTags,
    privacyStatus: $json.privacyStatus,
    categoryId: $json.categoryId
  }
};
return [{json: {...$json, manifestText: JSON.stringify(manifest)}, pairedItem: $input.item.pairedItem}];

const body = $json.body || {};
let payloadStr = body.payload;
if (!payloadStr && typeof body === 'string' && body.startsWith('payload=')) payloadStr = decodeURIComponent(body.slice('payload='.length));
if (!payloadStr) throw new Error("Missing Slack interactivity payload");
const payload = JSON.parse(payloadStr);
const raw = payload.actions?.[0]?.value || "";
const [status, runId] = raw.split("|");
if (!status || !runId) throw new Error("Missing status/runId in Slack button value");
return [{json: {status, runId, payload}}];

const m = $json;
const manifest = m.json || m;
const data = manifest;

return [{
  json: {
    runId: data.runId,
    videoUrl: data.videoUrl,
    logUrl: data.logUrl,
    youtubeTitle: data.youtube.title,
    youtubeDescription: data.youtube.description,
    youtubeTags: data.youtube.tags,
    privacyStatus: data.youtube.privacyStatus,
    categoryId: data.youtube.categoryId
  }
}];

